import { useState, useEffect } from "react";

export default function Diagnosis() {
  const [mounted, setMounted] = useState(false);
  const [symptoms, setSymptoms] = useState("");
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  if (!mounted) return null;

  const handleDiagnose = async () => {
    if (!symptoms) return alert("Please enter symptoms");

    setLoading(true);

    try {
      const res = await fetch("http://localhost:5000/api/diagnose", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ symptoms }),
      });

      const data = await res.json();
      setResult(data);
    } catch (error) {
      console.error(error);
      alert("Error contacting server");
    }

    setLoading(false);
  };

  return (
    <div style={styles.page}>
      <div style={styles.card}>
        <h1 style={styles.title}>AI Medical Diagnosis</h1>
        <p style={styles.subtitle}>
          Enter your symptoms and get suggested medical conditions.
        </p>

        <textarea
          style={styles.input}
          placeholder="Example: fever, headache, body pain..."
          value={symptoms}
          onChange={(e) => setSymptoms(e.target.value)}
        />

        <button style={styles.button} onClick={handleDiagnose}>
          {loading ? "Analyzing..." : "Diagnose"}
        </button>

        {result && (
          <div style={styles.result}>
            <h2 style={styles.resultTitle}>Diagnosis Result</h2>

            <div style={styles.resultBox}>
              <p>
                <strong>Possible Condition:</strong> {result.condition}
              </p>

              <p>
                <strong>Recommended Doctor:</strong> {result.doctor}
              </p>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

const styles = {
  page: {
    minHeight: "100vh",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    background:
      "linear-gradient(135deg,#6dd5ed,#2193b0,#3a7bd5,#00c6ff)",
    padding: "40px",
  },

  card: {
    background: "white",
    padding: "40px",
    borderRadius: "20px",
    width: "600px",
    boxShadow: "0px 10px 40px rgba(0,0,0,0.2)",
  },

  title: {
    textAlign: "center",
    fontSize: "32px",
    color: "#2193b0",
  },

  subtitle: {
    textAlign: "center",
    marginBottom: "20px",
    color: "#555",
  },

  input: {
    width: "100%",
    height: "120px",
    padding: "15px",
    borderRadius: "10px",
    border: "2px solid #2193b0",
    background: "#ffffff",
    color: "#000",
    fontSize: "16px",
    resize: "none",
  },

  button: {
    marginTop: "20px",
    width: "100%",
    padding: "15px",
    borderRadius: "10px",
    border: "none",
    background: "linear-gradient(90deg,#36d1dc,#5b86e5)",
    color: "white",
    fontSize: "18px",
    fontWeight: "bold",
    cursor: "pointer",
  },

  result: {
    marginTop: "30px",
  },

  resultTitle: {
    textAlign: "center",
    color: "#2193b0",
  },

  resultBox: {
    background: "#f4f9ff",
    padding: "20px",
    borderRadius: "12px",
    border: "1px solid #d0e7ff",
  },
};